import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch12: ScenarioQuestion[] = [
  q("sq-bg12-1",ip,"clinical_judgment","A patient develops acute respiratory failure requiring intubation.","What are the nursing priorities during intubation?","I would prepare: suction equipment, bag-valve mask with 100% O2, endotracheal tube of appropriate size plus one size smaller, laryngoscope, stylet, tape/securing device, end-tidal CO2 detector, and medications for rapid sequence intubation. During the procedure, I would assist with positioning, medication administration, monitoring SpO2 and heart rate, and tube verification.","Intubation preparation and nursing role.","intermediate"),
  q("sq-bg12-2",ip,"clinical_judgment","A patient develops cardiac tamponade after a cardiac catheterization.","How would you recognize post-cath tamponade?","Post-catheterization tamponade presents with hypotension, JVD, muffled heart sounds, and pulsus paradoxus. This is a catheterization complication requiring emergent pericardiocentesis. I would establish large-bore IV access, administer IV fluid bolus to maintain preload, prepare for pericardiocentesis, and have the resuscitation cart at bedside.","Post-catheterization tamponade emergency.","advanced"),
  q("sq-bg12-3",ip,"clinical_judgment","A patient develops cauda equina syndrome.","How would you recognize cauda equina syndrome?","Cauda equina syndrome presents with severe back pain, bilateral leg weakness, saddle anesthesia, and bowel/bladder dysfunction. This is a neurosurgical emergency requiring decompressive surgery within 48 hours to prevent permanent neurological damage. I would notify the neurosurgeon immediately, perform serial neurological assessments, and prepare for emergent MRI and surgery.","Cauda equina syndrome surgical emergency.","advanced"),
  q("sq-bg12-4",ip,"clinical_judgment","A patient with liver disease develops esophageal variceal bleeding.","How would you manage variceal hemorrhage?","I would establish two large-bore IVs, initiate volume resuscitation, administer octreotide IV per protocol, prepare for emergent endoscopy with banding, type and crossmatch for possible massive transfusion, insert an NG tube if ordered, and anticipate Sengstaken-Blakemore tube placement if endoscopic treatment fails. This is a life-threatening emergency.","Variceal hemorrhage emergency management.","advanced"),
  q("sq-bg12-5",ip,"clinical_judgment","A patient develops post-ERCP pancreatitis.","How would you manage post-ERCP pancreatitis?","Post-ERCP pancreatitis occurs in 3-10% of cases. I would assess for epigastric pain, check lipase levels, keep NPO, provide aggressive IV hydration, manage pain, and monitor for complications. Most cases are mild and self-limiting, but severe cases can develop necrosis. I would notify the gastroenterologist and trend lab values.","Post-ERCP pancreatitis assessment.","intermediate"),
  q("sq-bg12-6",ip,"behavioral","You are asked about handling mistakes.","How do you respond when you make a clinical error?","I immediately assess the patient for harm, implement corrective measures, notify the provider and charge nurse, document accurately, file a safety report, and reflect on what contributed to the error. I do not try to hide mistakes—transparency protects patients and enables system improvements. Every error is a learning opportunity.","Transparent error response.","beginner"),
  q("sq-bg12-7",ip,"behavioral","You are asked about teamwork philosophy.","What is your approach to teamwork in nursing?","Effective teamwork means: recognizing that no one can do it alone, communicating clearly and respectfully, supporting colleagues during difficult situations, accepting help without ego, and prioritizing patient outcomes over personal preferences. The best patient care happens when every team member contributes their unique expertise toward a common goal.","Team-first nursing philosophy.","beginner"),
  q("sq-bg12-8",ip,"scenario_responses","A patient asks about discharge planning.","How would you explain the discharge planning process?","Discharge planning starts the moment you are admitted. Our team—nurses, physicians, therapists, and case managers—works together to ensure you have everything you need when you go home: medications, follow-up appointments, home equipment, and any additional support services. We will teach you everything you need to know before you leave.","Comprehensive discharge planning explanation.","beginner"),
  q("sq-bg12-9",ip,"scenario_responses","A patient asks why nurses document so much.","How would you explain documentation importance?","Documentation is how we communicate your care story to every member of your team, even when I am not here. It ensures continuity—the night nurse knows exactly what happened during the day. It also protects you legally and helps us track your progress. When I document, I am creating a record that supports your best care.","Documentation purpose patient explanation.","beginner"),
  q("sq-bg12-10",ip,"star_examples","Describe adapting to unexpected change.","Tell me about adapting to a sudden change.","During clinical, our simulation lab transitioned to a new manikin system mid-semester. While others resisted, I volunteered to help test the new equipment, created a comparison guide for the team, and helped facilitate the transition. Embracing change rather than resisting it positioned me as a resource and leader.","Change adaptation with leadership initiative.","beginner"),
  q("sq-bg12-11",ws,"prioritization","A physician needs you to hold for orders while another patient is calling out in pain.","How would you manage competing physician and patient demands?","I would tell the physician: 'Can I call you back in 5 minutes? I have a patient in acute distress that I need to assess immediately.' Most physicians understand that patient emergencies take priority. I would assess the pain patient, implement standing orders if available, and return the physician's call promptly.","Physician communication during competing demands.","beginner"),
  q("sq-bg12-12",ws,"delegation","You need to delegate repositioning a bariatric patient.","How would you delegate care for a bariatric patient?","I would ensure adequate staff: 'We need a minimum of 4 people to safely reposition Mr. Thomas. Please use the bariatric repositioning equipment from the supply room. Do not attempt to move him with fewer people or without the assist device. Check his skin in all fold areas after repositioning and report any redness or breakdown.'","Bariatric patient safe handling delegation.","beginner"),
  q("sq-bg12-13",ws,"patient_safety","A patient develops a reaction to latex gloves.","How would you manage a latex allergy reaction?","I would remove all latex products immediately, assess the severity of the reaction, treat symptoms (antihistamines for mild, epinephrine for severe), place a latex allergy band on the patient, update the allergy section of the chart, ensure the room is made latex-free, and communicate the allergy to all care team members and dietary.","Latex allergy identification and environment modification.","beginner"),
  q("sq-bg12-14",ws,"patient_safety","A patient on a heparin drip has a significantly elevated aPTT.","How would you respond to a critically elevated aPTT?","I would stop the heparin drip, assess for signs of bleeding (check all access sites, urine, stool, neurological status), notify the physician immediately, prepare protamine sulfate in case of major bleeding, recheck aPTT per protocol, and resume heparin at a reduced rate only when ordered. I would monitor closely for delayed bleeding.","Critical aPTT with bleeding assessment.","intermediate"),
  q("sq-bg12-15",ws,"medication_error","A patient questions a pill that looks different from their usual medication.","How would you respond to a patient questioning their pill?","I would stop and verify. I would check the medication order, verify with pharmacy about manufacturer changes, and never dismiss a patient's concern. I would tell the patient: 'Thank you for speaking up. Let me verify this before you take it.' Patients who question their medications are the best safety partners.","Patient medication vigilance appreciation.","beginner"),
  q("sq-bg12-16",ws,"handoff_communication","Your patient had a significant family meeting today.","How would you include family meeting outcomes in handoff?","I would summarize: 'Family meeting held at 1400 with the physician, patient, wife, and two adult children. Goals of care discussed—patient wants to continue aggressive treatment. Family is supportive. Code status remains full code. Wife designated as healthcare proxy. The physician plans to reassess treatment response in 48 hours.'","Family meeting handoff communication.","beginner"),
  q("sq-bg12-17",ws,"difficult_coworkers","A colleague criticizes your patient to other staff.","How would you respond to a colleague disparaging your patient?","I would redirect immediately: 'Every patient deserves our professional respect regardless of their diagnosis or behavior. Let us focus on how we can provide the best care for this patient rather than making judgments.' Patient disparagement creates a hostile care environment that can unconsciously affect care quality.","Patient dignity protection from staff disparagement.","beginner"),
  q("sq-bg12-18",ws,"interdisciplinary_communication","A hospitalist wants to discharge but the surgeon wants to keep the patient.","How would you navigate conflicting discharge decisions?","I would clarify which service is the primary decision-maker and facilitate communication: 'I want to ensure the best plan for the patient. The hospitalist is recommending discharge today, but the surgical team wants continued observation. Can we arrange a brief conversation to align the care plan?' The patient should not receive conflicting instructions.","Primary service clarification for discharge conflicts.","intermediate"),
  q("sq-bg12-19",ct,"first_shift","You make a small mistake and your preceptor corrects you.","How would you respond to preceptor correction?","I would thank them sincerely: 'Thank you for catching that. I understand what I did wrong—I will make sure to [correct approach] next time.' I would not become defensive or make excuses. I would write down the correction in my learning notes and demonstrate the corrected behavior going forward. Graceful error acceptance accelerates learning.","Graceful correction acceptance.","beginner"),
  q("sq-bg12-20",ct,"new_nurse_anxiety","Your patient thanks you for your care and it makes you emotional.","How would you manage positive emotional moments?","I would accept the gratitude: 'Thank you—caring for you has been meaningful to me.' Positive emotional moments remind us why we chose nursing. I would save these moments in my memory for difficult days. It is okay to be moved by patient interactions—it means I am connected to my work in a meaningful way.","Positive emotional moment acceptance.","beginner"),
  q("sq-bg12-21",ct,"time_management","You have a patient going for a procedure at a specific time.","How would you prepare for a timed procedure?","I would work backward: know the procedure time, complete pre-procedure checklist (consent signed, labs done, site marked, NPO status verified, IV access, medications given/held per protocol), communicate with the procedure area, prepare the patient physically and emotionally, and ensure transport arrives on time. Being ready early prevents stressful delays.","Backward-planned procedure preparation.","beginner"),
  q("sq-bg12-22",ct,"documentation_challenges","You need to document a patient's response to a new medication.","How would you document medication response?","I would document: baseline assessment before medication administration, medication given (name, dose, route, time), time of reassessment, specific response indicators (pain scale change, blood pressure change, symptom improvement), any adverse effects observed, and overall effectiveness assessment. This documentation guides future medication decisions.","Medication response documentation framework.","beginner"),
  q("sq-bg12-23",ct,"critical_thinking_drills","A patient's AST and ALT are both elevated at 300.","What do elevated transaminases indicate?","AST and ALT of 300 (normal <40) indicate significant hepatocellular damage. Causes include: hepatitis (viral, drug, alcohol), ischemic liver injury, autoimmune hepatitis, and toxin exposure. I would check bilirubin, INR, and albumin for liver synthetic function, review medications for hepatotoxic drugs, and obtain hepatitis serologies. The degree of elevation and pattern guide the differential.","Transaminase elevation with hepatic function correlation.","intermediate"),
  q("sq-bg12-24",pd,"professional_boundaries","A discharged patient contacts you through social media.","How would you handle social media contact from a former patient?","I would not accept the connection. I would respond: 'I appreciate you reaching out. However, professional guidelines prevent me from connecting with patients on social media, even after discharge. If you need medical assistance, please contact your healthcare provider or the hospital directly.' Maintaining boundaries protects both parties.","Post-discharge social media boundary.","beginner"),
  q("sq-bg12-25",pd,"ethical_dilemmas","A patient asks you to withhold information from their physician.","How would you handle a request to withhold information from the physician?","I would explain: 'I understand your concern, but your physician needs accurate, complete information to make the best treatment decisions for you. Withholding information could lead to incorrect treatment that could harm you. Can we discuss what you are concerned about? Perhaps we can address it together with your doctor.'","Information transparency advocacy for patient safety.","intermediate"),
  q("sq-bg12-26",pd,"advocacy","A patient needs durable medical equipment upon discharge.","How would you ensure DME is arranged before discharge?","I would assess DME needs early, coordinate with case management and PT/OT for equipment recommendations, ensure physician orders are obtained, verify insurance coverage, coordinate delivery timing with discharge date, and provide equipment education. DME delivery confirmation before discharge prevents unsafe transitions and potential readmissions.","DME arrangement and education before discharge.","beginner"),
  q("sq-bg12-27",pd,"patient_communication","A patient asks about clinical trials.","How would you discuss clinical trial participation?","I would provide balanced information: 'Clinical trials offer access to new treatments that may be beneficial. Participation is completely voluntary—you can withdraw at any time. There are potential risks and benefits to consider. I can connect you with our research coordinator who can explain the specific trial, what it involves, and help you make an informed decision.'","Balanced clinical trial information.","beginner"),
  q("sq-bg12-28",pd,"workplace_bullying","You overhear a nurse making racist comments about a patient.","How would you address racist comments about patients?","I would intervene immediately: 'That comment is racist and unacceptable. Every patient deserves equitable, respectful care regardless of their race or ethnicity. Our professional obligation is to treat all patients with dignity.' I would report the incident to management. Racism in healthcare directly harms patient outcomes through biased care delivery.","Immediate racist comment intervention.","intermediate"),
  q("sq-bg12-29",cn,"job_offer_negotiation","An interviewer asks your greatest weakness as a nurse.","How would you answer the greatest weakness question?","I would be genuine: 'I sometimes take on too much myself rather than delegating. I am learning to trust my team members and share responsibilities appropriately. I have been actively practicing delegation by starting each shift with a clear task distribution plan. It is improving my efficiency and my team's engagement.'","Genuine weakness with active improvement.","beginner"),
  q("sq-bg12-30",cn,"probation_period","You want to make a strong impression on your evaluation.","What behaviors create the strongest evaluation outcomes?","Consistent performance beats sporadic excellence: arrive on time, complete assignments, accept feedback, show improvement, communicate proactively, and demonstrate safe clinical judgment. The most valued new graduates are not the flashiest—they are the ones who are reliable, honest, and show steady growth. Consistency builds trust.","Consistency-based evaluation impression.","beginner"),
  q("sq-bg12-31",ip,"clinical_judgment","A patient develops hyponatremic seizures.","How would you manage seizures from severe hyponatremia?","I would administer benzodiazepines for seizure control, then urgently correct sodium with 3% hypertonic saline (100-150 mL bolus over 10-20 minutes, may repeat twice). Target is a 4-6 mEq/L sodium increase to stop seizures. I would not correct more than 8 mEq/L in 24 hours to prevent osmotic demyelination. Seize monitoring and frequent sodium checks are essential.","Hyponatremic seizure management with correction limits.","advanced"),
  q("sq-bg12-32",ip,"clinical_judgment","A patient develops hospital-acquired Clostridioides difficile infection.","What makes C. diff challenging to manage?","C. diff spores are resistant to alcohol-based hand sanitizers—soap and water with friction is required for hand hygiene. The organism can survive on surfaces for months. I would implement contact precautions with dedicated equipment, use bleach-based environmental cleaning, educate staff about proper hand washing, and track antibiotic stewardship to prevent new cases.","C. diff environmental management challenges.","intermediate"),
  q("sq-bg12-33",ws,"patient_safety","A patient with a PEG tube develops tube displacement.","How would you manage PEG tube displacement?","I would not attempt reinsertion of a recently placed PEG tube—the tract may not be fully formed and reinsertion could perforate the peritoneum. I would cover the site with sterile gauze, mark the tube length if partially displaced, notify the gastroenterologist, hold tube feedings, and prepare for imaging or endoscopic replacement.","PEG displacement management with reinsertion caution.","intermediate"),
  q("sq-bg12-34",ws,"medication_error","A patient's potassium replacement was infused at an excessive rate.","Why is potassium infusion rate critical?","IV potassium infused too rapidly can cause fatal cardiac arrhythmias, chest tightness, burning at the infusion site, and cardiac arrest. Maximum peripheral infusion rate is typically 10 mEq/hour. Central lines allow faster rates with cardiac monitoring. I would monitor the ECG, assess the patient, slow or stop the infusion, and notify the provider immediately.","Potassium infusion rate safety.","intermediate"),
  q("sq-bg12-35",ct,"first_shift","You encounter medical equipment you have not used before.","How would you handle unfamiliar medical equipment?","I would not use equipment I have not been trained on. I would ask for training or demonstration from a competent colleague, review the manufacturer's instructions, locate the biomedical engineering contact for technical questions, and document my training. Using unfamiliar equipment without training risks patient safety and device damage.","Unfamiliar equipment training requirement.","beginner"),
  q("sq-bg12-36",ct,"critical_thinking_drills","A patient's alkaline phosphatase is 350 U/L.","What does elevated alkaline phosphatase indicate?","ALP of 350 (normal 44-147) suggests biliary or bone pathology. I would correlate with GGT (elevated in biliary disease but not bone), liver function tests, and clinical presentation. Isolated ALP elevation suggests bone disease (Paget's, metastases, fracture healing). Combined ALP and GGT elevation suggests biliary obstruction or cholestasis. Imaging may be needed.","ALP interpretation with GGT correlation.","intermediate"),
  q("sq-bg12-37",pd,"patient_communication","A patient is frustrated with the healthcare system.","How would you respond to systemic frustration?","I would validate without being defensive: 'I understand the healthcare system can be frustrating, and your feelings are valid. While I cannot fix the entire system, I can make sure that your experience here is as positive as possible. What can I do right now to help you feel better cared for?' Focus on actionable improvements.","System frustration validation with actionable support.","beginner"),
  q("sq-bg12-38",cn,"career_advancement","You want to understand healthcare economics.","Why should nurses understand healthcare economics?","Understanding healthcare costs, reimbursement models, and value-based care helps nurses: advocate for resource allocation, contribute to cost-effective care decisions, understand staffing rationale, participate meaningfully in quality improvement, and position themselves for leadership roles. Healthcare literacy makes nurses more effective advocates and leaders.","Healthcare economics nursing relevance.","intermediate"),
  q("sq-bg12-39",ip,"clinical_judgment","A patient develops ventricular tachycardia with a pulse.","How would you manage stable ventricular tachycardia?","For stable VT (pulse present, adequate BP, alert), I would call for help, prepare for cardioversion, administer amiodarone 150mg IV over 10 minutes, establish IV access if not present, place defibrillator pads, and monitor continuously. If the patient becomes unstable (hypotension, altered consciousness), immediate synchronized cardioversion is required.","Stable VT management versus unstable VT.","intermediate"),
  q("sq-bg12-40",ip,"clinical_judgment","A patient develops ventricular fibrillation.","What is the immediate response to VF?","VF is a non-perfusing rhythm requiring immediate defibrillation. I would call a code, begin CPR, defibrillate as soon as possible (360J monophasic, 120-200J biphasic), continue CPR, administer epinephrine every 3-5 minutes, and follow ACLS algorithm. Defibrillation within the first 3-5 minutes of VF significantly improves survival. Every minute of delay decreases survival by 7-10%.","VF immediate defibrillation protocol.","advanced"),
  q("sq-bg12-41",ws,"prioritization","You need to organize care for 4 patients with different acuity levels.","How would you create an efficient shift plan for 4 patients?","I would assess all patients briefly within the first 30 minutes, identify time-critical needs (medications, procedures, discharges), cluster care activities, schedule the most complex activities during peak staffing hours, and build flexibility for unexpected events. I would create a written timeline and adjust it as needed throughout the shift.","Four-patient shift planning methodology.","beginner"),
  q("sq-bg12-42",ws,"delegation","You need to delegate ambulation to a rehabilitating stroke patient.","How would you delegate stroke patient ambulation?","I would verify the PT's activity orders, specify: 'Please walk Mr. Kim with the rolling walker. He has left-sided weakness, so position yourself on his left side. Go no further than the nurses' station for this first walk. If he becomes dizzy, sit him down immediately. Do not leave him unattended. Report any new weakness, difficulty speaking, or confusion to me.'","Stroke-specific ambulation delegation with neuro checks.","beginner"),
  q("sq-bg12-43",ct,"new_nurse_anxiety","You are nervous about taking phone orders from physicians.","How would you build confidence with phone orders?","I would prepare before calling: have patient chart open, vital signs ready, use SBAR format. During the call, I would repeat orders back for verification, ask for clarification on anything unclear, and document immediately. Over time, this becomes natural. The key is preparation—knowing your patient's information reduces anxiety during physician interactions.","Phone order confidence building.","beginner"),
  q("sq-bg12-44",ct,"documentation_challenges","You need to document a skin assessment finding.","How would you document a detailed skin assessment?","I would document: location using anatomical landmarks, size in centimeters, shape, color, temperature compared to surrounding skin, moisture, turgor, presence of lesions (type, distribution, pattern), any open areas with measurements, and comparison to previous assessments. Precise skin documentation enables other nurses to detect changes.","Detailed skin assessment documentation.","beginner"),
  q("sq-bg12-45",pd,"ethical_dilemmas","A patient with a DNR develops a reversible condition.","How would you manage a reversible condition in a DNR patient?","DNR does not mean do not treat. I would aggressively treat reversible conditions within the patient's goals of care. For example, if a DNR patient develops anaphylaxis, I would administer epinephrine. DNR applies specifically to cardiac arrest—not to all medical interventions. I would clarify the patient's wishes about specific interventions.","DNR treatment scope clarification.","intermediate"),
  q("sq-bg12-46",cn,"career_advancement","You want to understand nurse residency programs.","What are the benefits of nurse residency programs?","Nurse residency programs provide structured orientation beyond basic precepting: evidence-based practice projects, clinical decision-making development, mentorship, cohort support, and graduated independence. Studies show residencies reduce first-year turnover by 50% and improve clinical competence. I would seek organizations that offer accredited residency programs.","Nurse residency program value.","beginner"),
  q("sq-bg12-47",ip,"clinical_judgment","A patient develops spinal epidural abscess.","How would you recognize a spinal epidural abscess?","Spinal epidural abscess presents with the classic triad: back pain, fever, and progressive neurological deficits. Risk factors include IV drug use, immunosuppression, and spinal procedures. This is a neurosurgical emergency—MRI confirms diagnosis and emergent decompression prevents permanent paralysis. I would ensure blood cultures are drawn and empiric antibiotics started immediately.","Spinal epidural abscess triad recognition.","advanced"),
  q("sq-bg12-48",ws,"patient_safety","A patient on telemetry has an artifact that looks like VT.","How would you differentiate artifact from true VT?","I would assess the patient immediately: if they are awake, alert, and asymptomatic, the rhythm is likely artifact from movement, loose leads, or poor contact. True VT causes hemodynamic changes. I would check lead placement, verify the rhythm on a 12-lead ECG, and not treat the monitor—treat the patient.","Artifact versus true arrhythmia assessment.","beginner"),
  q("sq-bg12-49",pd,"advocacy","A patient cannot afford their follow-up appointment copay.","How would you address follow-up care affordability barriers?","I would explore: sliding-scale clinics, community health centers (which charge based on ability to pay), hospital charity care programs, and telehealth options that may have lower copays. I would ensure the patient understands the importance of follow-up and help them find affordable alternatives. Financial barriers should not prevent necessary care.","Follow-up care affordability solutions.","beginner"),
  q("sq-bg12-50",cn,"performance_evaluation","You want to highlight safety contributions during evaluation.","How would you document patient safety contributions?","I would track: medication errors prevented (catches), falls prevented through intervention, near-misses reported, safety improvement suggestions, safety committee participation, and protocol adherence. Patient safety contributions demonstrate clinical vigilance and professional commitment. I would present these with specific examples during my evaluation.","Safety contribution documentation for evaluation.","beginner"),
  q("sq-bg12-51",ip,"clinical_judgment","A patient develops syndrome of irreversible lithium-effectuated neurotoxicity.","What is SILENT and how does it present?","SILENT occurs after lithium toxicity resolution, leaving persistent neurological deficits: cerebellar dysfunction, cognitive impairment, and extrapyramidal symptoms. The damage may be permanent even after lithium levels normalize. I would monitor neurological status closely after resolving lithium toxicity, provide rehabilitation referrals, and educate about this rare but devastating complication.","SILENT after lithium toxicity.","advanced"),
  q("sq-bg12-52",ws,"medication_error","A nurse scans a barcode but administers a different medication.","How would a barcode scan mismatch occur and how to prevent it?","Barcode scanning only works if the nurse verifies the scanned medication matches what they are actually administering. Scanning first and then grabbing a different medication from the drawer defeats the purpose. I would ensure I scan and administer the same item, verify the screen confirmation, and never bypass scan alerts without investigation.","Barcode scanning integrity verification.","beginner"),
  q("sq-bg12-53",ct,"critical_thinking_drills","A patient's GGT is 200 U/L.","What does elevated GGT indicate when combined with elevated ALP?","GGT of 200 (normal 0-65) combined with elevated ALP strongly suggests hepatobiliary pathology rather than bone disease. GGT is elevated in bile duct obstruction, liver disease, and alcohol use. If ALP is elevated but GGT is normal, the ALP elevation is likely from bone. GGT helps differentiate the source of ALP elevation.","GGT as ALP source differentiator.","intermediate"),
  q("sq-bg12-54",pd,"patient_communication","A patient is frustrated about repeated blood draws.","How would you address blood draw frustration?","I would validate: 'I understand it is frustrating to be stuck multiple times. Each blood draw gives us important information about how your body is responding to treatment. Let me see if we can coordinate the timing so fewer draws are needed, or if any can be done from your existing IV. Your comfort matters to us.'","Blood draw coordination for patient comfort.","beginner"),
  q("sq-bg12-55",cn,"career_advancement","You want to develop your research appraisal skills.","How would you learn to critically appraise nursing research?","I would take a research methods course, practice reading primary research articles with a critical appraisal tool, participate in journal clubs, learn about study design hierarchy, understand statistical significance versus clinical significance, and ask mentors to guide my analysis. Critical appraisal skills are essential for evidence-based practice.","Research appraisal skill development.","beginner"),
  q("sq-bg12-56",ip,"clinical_judgment","A patient develops Ogilvie's syndrome.","What is Ogilvie's syndrome?","Ogilvie's syndrome is acute colonic pseudo-obstruction without mechanical cause, often post-operative or in critically ill patients. The colon dilates massively, risking perforation. I would monitor serial abdominal X-rays for cecal diameter (>10-12 cm increases perforation risk), ensure NPO status, initiate neostigmine per protocol, and prepare for possible colonoscopic decompression.","Ogilvie's syndrome cecal monitoring.","advanced"),
  q("sq-bg12-57",ws,"handoff_communication","You need to give report on a patient with a complicated medication schedule.","How would you communicate complex medication timing?","I would organize by time: 'His medication schedule is complex: 0600 levothyroxine on empty stomach, 0800 metoprolol, lisinopril, and atorvastatin with breakfast, 1200 insulin lispro before lunch (check glucose first), 1400 IV vancomycin due (trough was drawn at 0500), 2000 insulin glargine. The key timing issue is the vancomycin—the next trough is due before tomorrow's dose.'","Time-organized complex medication handoff.","beginner"),
  q("sq-bg12-58",ct,"time_management","You are responsible for multiple patients receiving IV antibiotics.","How would you manage multiple simultaneous IV antibiotic schedules?","I would create a timeline showing all antibiotic due times, identify overlaps requiring sequential infusion, ensure compatibility if co-infusion is needed, pre-program pumps when possible, and stagger start times to avoid all infusions ending simultaneously. I would set alerts for infusion completion and prioritize time-sensitive antibiotics.","IV antibiotic schedule coordination.","beginner"),
  q("sq-bg12-59",pd,"ethical_dilemmas","A patient's power of attorney makes decisions inconsistent with the patient's values.","How would you address POA decisions misaligned with patient values?","I would document the patient's previously stated values and wishes, request an ethics consultation, present my concerns to the healthcare team, and advocate for the patient's known preferences. While the POA has legal authority, they are obligated to make decisions consistent with the patient's expressed wishes, not their own preferences.","POA alignment with patient values advocacy.","advanced"),
  q("sq-bg12-60",cn,"career_advancement","You want to develop your grant writing skills.","How would you learn grant writing for nursing research?","I would attend grant writing workshops offered by my institution, study successful grant applications, partner with experienced researchers as co-investigators, start with small internal grants to build experience, and seek mentorship from funded nurse researchers. Grant writing is a specialized skill that opens doors for research funding and career advancement.","Grant writing skill development.","intermediate"),
  q("sq-bg12-61",ip,"clinical_judgment","A post-thyroidectomy patient develops stridor.","What causes post-thyroidectomy stridor?","Post-thyroidectomy stridor can indicate: recurrent laryngeal nerve injury causing vocal cord paralysis, hematoma compressing the airway, or hypocalcemia from parathyroid damage causing laryngospasm. This is an airway emergency. I would assess voice quality, check calcium level, prepare for possible emergency airway management, and have a tracheostomy tray at bedside.","Post-thyroidectomy stridor differential with airway preparation.","advanced"),
  q("sq-bg12-62",ws,"patient_safety","A patient on anticoagulation falls and hits their head.","Why is a head injury in an anticoagulated patient especially concerning?","Anticoagulated patients have significantly higher risk of intracranial hemorrhage from head trauma, even from seemingly minor falls. I would perform serial neurological assessments, obtain a stat CT head, check anticoagulation levels, hold anticoagulation, notify the provider immediately, and monitor for signs of increasing intracranial pressure for at least 24 hours.","Anticoagulated head injury heightened concern.","intermediate"),
  q("sq-bg12-63",ct,"documentation_challenges","You need to document a patient's functional assessment.","What should a functional assessment include?","I would document: mobility level (bed mobility, transfers, ambulation distance and assistive devices), ADL independence (bathing, dressing, toileting, feeding), cognitive status, communication ability, fall risk assessment score, skin integrity, nutritional intake, and comparison to pre-hospitalization baseline. This assessment guides discharge planning and therapy needs.","Comprehensive functional assessment documentation.","beginner"),
  q("sq-bg12-64",pd,"professional_boundaries","A patient's family gives you expensive chocolates.","How would you handle a mid-care gift?","I would follow facility policy. If small gifts are acceptable, I might accept the chocolates for the unit to share. For expensive gifts, I would redirect: 'That is so thoughtful. Our unit policy limits what I can accept personally, but I would love to share these with the team who has been caring for your family member.'","Unit-sharing gift redirection.","beginner"),
  q("sq-bg12-65",cn,"probation_period","You feel ready for independent practice before your orientation ends.","How would you handle feeling ready before orientation is complete?","I would appreciate the remaining orientation time as an opportunity to refine skills with a safety net. I would discuss it with my manager: 'I feel confident with most aspects of care. Could we focus the remaining orientation time on advanced skills or complex scenarios that will strengthen my practice for when I am truly independent?'","Advanced orientation utilization when feeling ready.","beginner"),
  q("sq-bg12-66",ip,"clinical_judgment","A patient develops contrast allergy during cardiac catheterization.","How would you manage contrast allergy during a procedure?","I would alert the procedural team immediately, administer epinephrine IM for anaphylaxis, provide IV diphenhydramine and methylprednisolone, ensure patent airway, support hemodynamics with IV fluids and vasopressors if needed, and document the reaction in the allergy section. Future contrast procedures will require premedication protocol.","Procedural contrast allergy emergency management.","intermediate"),
  q("sq-bg12-67",ws,"delegation","You need to delegate monitoring continuous bladder irrigation.","How would you delegate CBI monitoring?","I would instruct: 'Monitor Mr. Lee's continuous bladder irrigation. The irrigant should flow fast enough to keep the drainage light pink to clear. If the drainage becomes dark red, has clots, or stops flowing, notify me immediately—the catheter may be obstructed. Do not adjust the catheter position. Record irrigation input and drainage output every hour.'","CBI monitoring delegation with obstruction indicators.","intermediate"),
  q("sq-bg12-68",ct,"critical_thinking_drills","A patient's amylase is 500 U/L.","How does amylase compare to lipase for pancreatitis diagnosis?","Amylase of 500 (normal 30-110) suggests pancreatitis but is less specific than lipase. Amylase rises within 6-12 hours but normalizes within 3-5 days, while lipase remains elevated longer. Amylase can also be elevated in parotitis, bowel obstruction, and renal failure. Lipase is preferred for pancreatitis diagnosis due to higher specificity for pancreatic origin.","Amylase versus lipase specificity comparison.","intermediate"),
  q("sq-bg12-69",pd,"advocacy","A patient needs physical therapy but insurance only covers limited sessions.","How would you advocate for adequate PT coverage?","I would work with the case manager to appeal for additional sessions, ensure thorough documentation of functional deficits and therapy goals, explore alternative funding through hospital charity programs or community resources, and provide a home exercise program to supplement limited sessions. Patients should not be denied recovery due to coverage limitations.","PT coverage advocacy with alternative resources.","beginner"),
  q("sq-bg12-70",cn,"career_advancement","You want to understand healthcare quality metrics.","Why should nurses understand quality metrics?","Quality metrics (readmission rates, HCAHPS scores, infection rates, fall rates, pressure injury rates) directly reflect nursing care quality and impact hospital reimbursement. Understanding these metrics helps nurses: contribute to quality improvement, understand the connection between individual care and system outcomes, and demonstrate their value in measurable terms.","Quality metrics nursing relevance.","beginner"),
  q("sq-bg12-71",ip,"clinical_judgment","A patient develops Prinzmetal's angina.","What differentiates Prinzmetal's from typical angina?","Prinzmetal's (variant) angina occurs at rest, often in the early morning, from coronary artery vasospasm rather than fixed obstruction. ECG shows transient ST elevation during episodes. Treatment includes calcium channel blockers and nitrates. Beta-blockers can worsen Prinzmetal's by allowing unopposed alpha-mediated vasoconstriction. Differentiating from STEMI is critical.","Prinzmetal's angina with beta-blocker contraindication.","advanced"),
  q("sq-bg12-72",ws,"patient_safety","A patient develops CAUTI.","How would you prevent catheter-associated UTI?","CAUTI prevention includes: insert only when indicated, use aseptic technique during insertion, maintain closed drainage system, keep the bag below the bladder, perform daily catheter necessity assessments, remove as soon as possible, perform regular perineal hygiene, and ensure adequate fluid intake. Each day with a catheter increases UTI risk by 3-7%.","CAUTI prevention bundle.","beginner"),
  q("sq-bg12-73",ct,"new_nurse_anxiety","You feel your nursing school friends are progressing faster than you.","How do you handle feeling behind your peers?","I would remember that career trajectories are individual—different units, patient populations, and experiences create different learning curves. A nurse in the ICU develops different skills at different rates than one in rehab. I would focus on my own growth metrics rather than comparing to others' paths. My timeline is valid.","Individual trajectory validation.","beginner"),
  q("sq-bg12-74",pd,"patient_communication","A patient expresses anger about their diagnosis.","How would you respond to a patient's anger about their illness?","I would let them express their feelings without interrupting or trying to fix it: 'You have every right to be angry. This is not what you planned for your life, and it is unfair. I am here to listen whenever you need to talk, and I am committed to helping you through this in whatever way I can.'","Anger validation without fixing.","beginner"),
  q("sq-bg12-75",cn,"job_offer_negotiation","You want to ask about the unit's turnover rate.","How would you inquire about unit retention during an interview?","I would ask diplomatically: 'Can you tell me about the tenure of nurses on this unit? What do nurses typically say about why they stay? What does professional development look like for someone who plans to build their career here?' These questions reveal turnover without asking directly about negative statistics.","Indirect retention inquiry approach.","beginner"),
  q("sq-bg12-76",ip,"clinical_judgment","A patient on amiodarone develops pulmonary toxicity.","How would you recognize amiodarone pulmonary toxicity?","Amiodarone pulmonary toxicity presents with progressive dyspnea, dry cough, fever, and bilateral infiltrates on chest X-ray—often mimicking pneumonia. It can occur months to years after starting amiodarone. I would report symptoms to the physician, anticipate chest CT, PFTs, and possible amiodarone discontinuation. This is a serious and potentially fatal side effect.","Amiodarone pulmonary toxicity recognition.","advanced"),
  q("sq-bg12-77",ws,"interdisciplinary_communication","A patient needs a multidisciplinary family meeting.","How would you organize a family meeting?","I would identify all necessary participants (physician, nurse, SW, chaplain, PT, patient, family), coordinate schedules, prepare the family about what to expect, ensure a private meeting space, prepare my nursing assessment and observations, and have resources available for the outcomes discussed. I would document the meeting thoroughly.","Family meeting organization and preparation.","intermediate"),
  q("sq-bg12-78",ct,"critical_thinking_drills","A patient's troponin is trending: 0.04, 0.12, 0.35 over 6 hours.","What does a rising troponin trend indicate?","A rising troponin trend (0.04→0.12→0.35) with a rise-and-fall pattern is characteristic of acute myocardial injury, most commonly acute MI. The pattern is more diagnostically significant than a single elevated value, which could represent chronic elevation from other conditions. I would correlate with ECG changes, chest pain characteristics, and ensure cardiology consultation.","Troponin trending pattern for acute MI.","intermediate"),
  q("sq-bg12-79",pd,"ethical_dilemmas","A patient on hospice asks to be readmitted for aggressive treatment.","How would you manage a hospice patient wanting to revoke hospice?","Patients can revoke hospice at any time—it is their right. I would ensure they understand the implications: loss of hospice benefits, return to traditional coverage, and the clinical reality of their condition. I would not judge their decision or discourage revocation. I would facilitate the process and ensure continuity of care during the transition.","Hospice revocation right support.","intermediate"),
  q("sq-bg12-80",cn,"career_advancement","You want to understand advanced nursing certifications.","What advanced certifications should you consider after 2 years?","After 2 years of experience: specialty certification relevant to your unit (CCRN for ICU, CEN for ED, CMSRN for med-surg, PCCN for progressive care), wound care WOC, stroke SCRN, or cardiac vascular CVRN. Certifications demonstrate expertise, increase salary, and improve patient outcomes. Most require passing an exam and maintaining CE for renewal.","Advanced certification options by specialty.","beginner"),
  q("sq-bg12-81",ip,"clinical_judgment","A patient develops severe sepsis with lactate of 4.","What does the 3-hour sepsis bundle require?","Within 3 hours: measure lactate level, obtain blood cultures before antibiotics, administer broad-spectrum antibiotics, and provide 30 mL/kg IV crystalloid for hypotension or lactate ≥4. The 6-hour bundle adds: vasopressors for persistent hypotension, reassess volume status and tissue perfusion, and remeasure lactate if initially elevated. Time to antibiotics is the most critical element.","Sepsis bundle timeline requirements.","intermediate"),
  q("sq-bg12-82",ws,"patient_safety","A post-surgical patient develops subcutaneous emphysema.","What does subcutaneous emphysema indicate post-surgically?","Subcutaneous emphysema—crepitus palpated under the skin—indicates air escaping from the airway, lungs, or bowel into subcutaneous tissue. Post-surgically, this could indicate pneumothorax, tracheal injury, or esophageal perforation. I would assess respiratory status, obtain imaging, mark the extent of emphysema on the skin, and monitor for expansion. This finding requires urgent evaluation.","Subcutaneous emphysema assessment and marking.","intermediate"),
  q("sq-bg12-83",ct,"documentation_challenges","You need to document a change in patient's code status.","How would you document a code status change?","I would document: 'Code status discussed with patient/family by Dr. [name] at [time]. Patient has decision-making capacity as demonstrated by [assessment]. After discussion of prognosis, treatment options, and potential outcomes, patient changed code status from Full Code to DNR/DNI. Patient verbalized understanding of the implications. Order entered and verified. Allergy band updated. POLST/MOLST form completed.'","Code status change documentation with capacity.","intermediate"),
  q("sq-bg12-84",pd,"patient_communication","A patient misunderstands their medication purpose.","How would you correct a medication purpose misunderstanding?","I would clarify gently: 'I want to make sure you understand why you are taking this medication. You mentioned it is for your blood pressure, but actually this medication is prescribed for your diabetes. Let me go through each of your medications and what they do, so you know exactly why you are taking each one.'","Gentle medication purpose education.","beginner"),
  q("sq-bg12-85",cn,"career_advancement","You want to develop leadership in shared governance.","What is shared governance and how do you participate?","Shared governance is a model where bedside nurses participate in clinical and organizational decision-making through unit-based councils and hospital-wide committees. I would volunteer for my unit's practice council, propose evidence-based changes, participate actively in meetings, and follow through on assigned action items. This develops leadership skills and directly improves patient care.","Shared governance participation and leadership.","beginner"),
  q("sq-bg12-86",ip,"clinical_judgment","A patient develops hemolytic anemia from prosthetic heart valve.","How does a mechanical valve cause anemia?","Mechanical heart valve hemolysis occurs when RBCs are damaged by shear forces through the valve. Signs include elevated LDH, decreased haptoglobin, schistocytes on peripheral smear, and anemia. I would monitor hemoglobin, reticulocyte count, and hemolysis markers. Severe hemolysis may indicate valve dysfunction requiring echocardiographic evaluation. Iron and folate supplementation support red cell production.","Prosthetic valve hemolysis monitoring.","advanced"),
  q("sq-bg12-87",ws,"delegation","You need a CNA to assist with a dressing change.","How would you delegate dressing change assistance?","I would specify: 'I need you to help me with Mrs. Park's abdominal wound dressing change. Your role is to maintain a sterile field, hand me supplies, and help position the patient. Do not touch the wound or sterile supplies directly. If you need to step away, let me know so I can maintain the sterile field.'","Sterile dressing assistance delegation.","beginner"),
  q("sq-bg12-88",ct,"time_management","You have a new admission, a discharge, and a patient returning from surgery simultaneously.","How would you manage three major events simultaneously?","I would prioritize: post-surgical patient first (immediate assessment needs), then the new admission (safety assessment), then the discharge (can wait briefly). I would delegate: have a CNA obtain admission vitals, request help from a colleague for one patient, and communicate with the discharge patient about a brief delay. Transparent communication manages expectations.","Triple event management with prioritization and delegation.","intermediate"),
  q("sq-bg12-89",pd,"workplace_bullying","A senior nurse tells you that you will never be a good nurse.","How would you respond to discouraging personal attacks?","I would not internalize the comment: 'I appreciate constructive feedback, but personal judgments about my future are not helpful. If you have specific clinical concerns about my practice, I am open to discussing them. Otherwise, I would prefer we maintain a professional, supportive working relationship.' I would document the comment and discuss with my manager.","Personal attack boundary with documentation.","intermediate"),
  q("sq-bg12-90",cn,"performance_evaluation","You want to negotiate continued education support during evaluation.","How would you negotiate for education benefits?","I would present the mutual benefit: 'I would like to pursue my CCRN certification within the next year. The certification improves patient outcomes and demonstrates unit competency. I am requesting support through: exam fee coverage, study materials, and one paid study day. This investment benefits both my professional growth and the unit's quality metrics.'","Mutual benefit education benefit negotiation.","beginner"),
  q("sq-bg12-91",ip,"clinical_judgment","A patient develops acute kidney injury from rhabdomyolysis.","How does rhabdomyolysis cause AKI?","Myoglobin released from damaged muscles is filtered by the kidneys and precipitates in the tubules, causing obstruction and direct tubular injury. Prevention requires aggressive IV hydration to maintain high urine output, alkalinizing the urine with sodium bicarbonate if ordered, monitoring CK and renal function, and avoiding nephrotoxic medications.","Rhabdomyolysis renal protection mechanism.","advanced"),
  q("sq-bg12-92",ws,"patient_safety","A patient's feeding tube pump alarms frequently.","How would you troubleshoot enteral feeding pump alarms?","I would check: tube position verification, formula viscosity and temperature, tubing for kinks, pump settings match the order, and bag height. For occlusion alarms, I would flush with warm water. For positional alarms, I would reposition the patient. If alarms continue after troubleshooting, I would replace the pump and notify the provider if feeding is significantly interrupted.","Enteral feeding pump troubleshooting.","beginner"),
  q("sq-bg12-93",ct,"critical_thinking_drills","A patient's hemoglobin A1c has improved from 12% to 7.5% over 3 months.","What does HbA1c improvement indicate?","Improvement from 12% to 7.5% indicates significantly better glycemic control—average blood glucose dropped from approximately 300 to approximately 170. I would celebrate this progress with the patient, reinforce successful behaviors, continue monitoring, and adjust goals toward the target of <7%. This improvement significantly reduces risk of diabetic complications.","HbA1c improvement celebration with continued monitoring.","beginner"),
  q("sq-bg12-94",pd,"ethical_dilemmas","A family requests aggressive care for a brain-dead patient.","How would you navigate care for a brain-dead patient whose family requests continued treatment?","Brain death is legal death in all 50 states. I would ensure the family understands the diagnosis through clear, compassionate communication from the physician, involve social work and chaplain, allow time for processing, offer organ donation counseling, and follow facility and legal protocols. Once brain death is declared, there is no legal obligation to continue treatment, though sensitivity is essential.","Brain death family communication and legal obligations.","advanced"),
  q("sq-bg12-95",cn,"career_advancement","You are interested in flight nursing.","What does flight nursing require?","Flight nurses work on helicopter and fixed-wing air medical services. Requirements include: 3-5 years of ED or ICU experience, ACLS/PALS/NRP certifications, CFRN certification, physical fitness for confined-space patient care, comfort with high-acuity autonomous practice, and ability to function in challenging environments. Flight nursing is one of the most autonomous and demanding nursing roles.","Flight nursing career requirements.","intermediate"),
  q("sq-bg12-96",ip,"clinical_judgment","A patient develops thrombophilia.","How would you manage a patient with thrombophilia?","Thrombophilia includes conditions like Factor V Leiden, prothrombin gene mutation, and protein C/S deficiency that increase clotting risk. Management depends on the specific disorder and clinical history: long-term anticoagulation for recurrent VTE, prophylactic anticoagulation during high-risk periods, patient education about risk factors, and genetic counseling for family members.","Thrombophilia management and family counseling.","intermediate"),
  q("sq-bg12-97",ws,"handoff_communication","A patient's family has been updated about a change in condition.","How would you communicate family awareness during handoff?","I would include: 'I updated Mrs. Garcia's daughter at 1600 about the CT results showing progression of her mother's tumor. She was very emotional and asked about hospice. I arranged a meeting with palliative care for tomorrow at 1000. The patient does not yet know—her daughter wants to be present when the physician discusses it.'","Family emotional state handoff communication.","beginner"),
  q("sq-bg12-98",ct,"new_nurse_anxiety","You have a recurring nightmare about a clinical mistake.","How would you address recurring work nightmares?","I would recognize this as a sign of clinical stress that needs attention. I would practice sleep hygiene, discuss the nightmares with a trusted colleague or EAP counselor, use relaxation techniques before bed, and assess whether the nightmares correlate with specific clinical stressors. If nightmares persist, professional support may help process underlying anxiety.","Work nightmare professional support seeking.","beginner"),
  q("sq-bg12-99",pd,"patient_communication","A patient asks about alternative providers after a negative experience.","How would you help a patient find a new provider?","I would validate their experience: 'I am sorry you had a negative experience. You deserve a provider you trust and feel comfortable with. I can help you understand your options for changing providers within your insurance network. Your patient advocate can also help you file a concern about your experience if you wish.'","Provider change support with advocacy.","beginner"),
  q("sq-bg12-100",cn,"career_advancement","You want to understand magnet hospital designation.","What is Magnet designation and why does it matter?","Magnet designation from ANCC recognizes healthcare organizations for nursing excellence, quality patient outcomes, and innovative professional practice. Magnet hospitals typically have: better nurse-to-patient ratios, higher nurse satisfaction, lower turnover, and better patient outcomes. Working at a Magnet hospital provides professional development opportunities and demonstrates your commitment to excellence.","Magnet hospital designation significance.","beginner"),
];
